usort( $attachments, function ( $a, $b ) use($order) {
                $first_source = $a->date ?? '';
                $second_source = $b->date ?? '';
                $first = ( strtotime( $first_source ) ?: 0 );
                $second = ( strtotime( $second_source ) ?: 0 );
                $comparison = 0;
                if ( $first < $second ) {
                    $comparison = -1;
                } elseif ( $first > $second ) {
                    $comparison = 1;
                }
                return ( 'ASC' === $order ? $comparison : -$comparison );
            } )

usort( $attachments, function ( $a, $b ) use($order) {
                $first_source = $a->modified ?? '';
                $second_source = $b->modified ?? '';
                $first = ( strtotime( $first_source ) ?: 0 );
                $second = ( strtotime( $second_source ) ?: 0 );
                $comparison = 0;
                if ( $first < $second ) {
                    $comparison = -1;
                } elseif ( $first > $second ) {
                    $comparison = 1;
                }
                return ( 'ASC' === $order ? $comparison : -$comparison );
            } )

usort( $attachments, function ( $a, $b ) use($order) {
                $comparison = strnatcasecmp( $a->title ?? '', $b->title ?? '' );
                if ( 'ASC' === $order ) {
                    return $comparison;
                }
                return -$comparison;
            } )

array_filter( $attachments, static function ( $attachment ) {
